// JWT-Decoder. Dekodiert header+payload (base64url), zeigt exp/iat. Keine Signaturpruefung.
async function run(input) {
  var token = String((input && input.token) || '');
  var parts = token.split('.');
  if (parts.length < 2) return { fehler: 'Kein gueltiges JWT (header.payload.signature).' };
  function b64url(s) {
    s = s.replace(/-/g, '+').replace(/_/g, '/');
    while (s.length % 4) s += '=';
    return decodeURIComponent(escape(atob(s)));
  }
  var header, payload;
  try { header = JSON.parse(b64url(parts[0])); payload = JSON.parse(b64url(parts[1])); }
  catch (e) { return { fehler: 'JWT konnte nicht dekodiert werden.' }; }
  var out = {
    header: header,
    payload: payload,
    signaturVorhanden: parts.length >= 3 && parts[2].length > 0,
    hinweis: 'Signatur wurde NICHT verifiziert (kein Secret).'
  };
  if (payload && typeof payload.exp === 'number') {
    out.abgelaufen = Date.now() > payload.exp * 1000;
    out.ablaufDatum = new Date(payload.exp * 1000).toISOString();
  }
  if (payload && typeof payload.iat === 'number') {
    out.ausstellungsDatum = new Date(payload.iat * 1000).toISOString();
  }
  return out;
}
